const clientData = $('Current Client Domain List').all();
const seoTasks = $input.all();

const records = [];
let clientIndex = 0;


seoTasks.forEach(task => {
  // Make sure the path exists and has data
  const tasksArray = task?.json?.tasks;
  if (!tasksArray || tasksArray.length === 0) return;

  const resultArray = tasksArray[0]?.result;
  if (!resultArray || resultArray.length === 0) return;

  const result = resultArray[0];

  const clientInfo = clientData[clientIndex];
  if (!clientInfo) return;

  records.push({
    client_id: clientInfo.json.client_id,
    client_domain_id: clientInfo.json.client_domain_id,
    client_domain: clientInfo.json.client_domain,
    rival_domain_id: clientInfo.json.id,
    target: result.target,
    rank: result.rank,
    backlinks: result.backlinks,
    backlinks_spam_score: result.backlinks_spam_score,
    crawled_pages: result.crawled_pages,
    broken_backlinks: result.broken_backlinks,
    broken_pages: result.broken_pages,
    referring_domains: result.referring_domains,
    referring_domains_nofollow: result.referring_domains_nofollow,
    referring_main_domains: result.referring_main_domains,
    referring_main_domains_nofollow: result.referring_main_domains_nofollow,
    referring_ips: result.referring_ips,
    referring_subnets: result.referring_subnets,
    referring_pages: result.referring_pages,
    referring_pages_nofollow: result.referring_pages_nofollow,
    referring_links_tld: result.referring_links_tld,
    referring_links_types: result.referring_links_types,
    referring_links_attributes: result.referring_links_attributes,
    referring_links_platform_types: result.referring_links_platform_types,
    referring_links_semantic_locations: result.referring_links_semantic_locations,
    referring_links_countries: result.referring_links_countries,
    history_date: new Date().toISOString().split('T')[0]
  });

  clientIndex++;
});

return records;

// Get the first input item (the full client object)
const input = $input.first().json;

const cleanDomain = url => {
  if (!url) return "";
  // Remove protocol
  url = url.replace(/^https?:\/\//, "");
  // Remove www.
  url = url.replace(/^www\./, "");
  // Keep only domain part (in case path exists)
  url = url.split("/")[0];
  return url;
};

// Collect all rival domains with their parent client and domain info
const allRivals = [];

(input.client_domains || []).forEach(domain => {
  allRivals.push({
      client_id: input.client_id || input.id,
      client_name: input.client_name || input.name,
      client_domain_id: domain.client_domain_id || domain.id,
      client_domain_title: domain.client_domain_title || domain.title,
      client_domain: cleanDomain(domain.client_domain) || domain.target_url,
      id: domain.client_domain_id,
      rival_domain_title: domain.client_domain_title || domain.title,
      rival_domain: cleanDomain(domain.client_domain) || domain.target_url,
      current_time : domain.current_time,
      last_six_month_date : domain.last_six_month_date
    });
  (domain.rival_domains || []).forEach(rival => {
    allRivals.push({
      client_id: input.client_id || input.id,
      client_name: input.client_name || input.name,
      client_domain_id: domain.client_domain_id || domain.id,
      client_domain_title: domain.client_domain_title || domain.title,
         current_time : domain.current_time,
      last_six_month_date : domain.last_six_month_date,
      client_domain: cleanDomain(domain.client_domain) || domain.target_url,
      id: rival.id,
      rival_domain_title: rival.rival_domain_title || rival.title,
      rival_domain: cleanDomain(rival.rival_domain) || rival.target_url
    });
  });
});

// Return as n8n items
return allRivals.map(r => ({ json: r }));

// Generate current timestamp
function getStartDate({ monthsAgo = 0, hoursAgo = 0, minDate = "2019-01-01" } = {}) {
  const now = new Date();

  // Subtract months or hours if provided
  if (monthsAgo) now.setMonth(now.getMonth() - monthsAgo);
  if (hoursAgo) now.setHours(now.getHours() - hoursAgo);

  // Use minDate if calculated date is before it
  const min = new Date(minDate);
  const start = now < min ? min : now;

  const pad = n => (n < 10 ? "0" + n : n);
  const formatted = `${start.getFullYear()}-${pad(start.getMonth() + 1)}-${pad(start.getDate())}`;

  return formatted;
}

const current = getStartDate();                    
// const last24Hours = getFormattedDate({ hoursAgo: 24 }); 
const lastMonth = getStartDate({ monthsAgo: 1 });  
// const last6Months = getStartDate({ monthsAgo: 6 }); 

// Get all input clients
const clients = $input.all().map(item => item.json);

// Build grouped output
const result = [];

clients.forEach(client => {
  const clientData = {
    client_id: client.id,
    client_name: client.name,
    client_domains: []
  };

  (client.client_domains || []).forEach(domain => {
    if (!domain.rival_domains || domain.rival_domains.length === 0) return; // skip domains with no rivals

    clientData.client_domains.push({
      client_domain_id: domain.id,
      client_domain_title: domain.title,
      client_domain: domain.target_url,
      current_time : current,
      last_six_month_date : lastMonth,
      rival_domains: domain.rival_domains.map(rival => ({
        id: rival.id,
        rival_domain_title: rival.title,
        rival_domain: rival.target_url
      }))
    });
  });

  // only push clients that actually have domains with rivals
  if (clientData.client_domains.length > 0) {
    result.push(clientData);
  }
});

// Return as n8n items
return result.map(r => ({ json: r }));
